  6→package metricstore
  7→
  8→import (
  9→	"context"
 10→	"errors"
 11→	"fmt"
 12→	"os"
 13→	"path/filepath"
 14→	"sync"
 15→	"sync/atomic"
 16→	"time"
 17→
 18→	cclog "github.com/ClusterCockpit/cc-lib/v2/ccLogger"
 19→)
 20→
 21→// Worker for either Archiving or Deleting files
 22→
 23→func CleanUp(wg *sync.WaitGroup, ctx context.Context) {
 24→	if Keys.Cleanup.Mode == "archive" {
 25→		// Run as Archiver
 26→		cleanUpWorker(wg, ctx,
 27→			Keys.RetentionInMemory,
 28→			"archiving",
 29→			Keys.Cleanup.RootDir,
 30→			false,
 31→		)
 32→	} else {
 33→		// Run as Deleter
 34→		cleanUpWorker(wg, ctx,
 35→			Keys.RetentionInMemory,
 36→			"deleting",
 37→			"",
 38→			true,
 39→		)
 40→	}
 41→}
 42→
 43→// cleanUpWorker takes simple values to configure what it does
 44→func cleanUpWorker(wg *sync.WaitGroup, ctx context.Context, interval string, mode string, cleanupDir string, delete bool) {
 45→	wg.Go(func() {
 46→
 47→		d, err := time.ParseDuration(interval)
 48→		if err != nil {
 49→			cclog.Fatalf("[METRICSTORE]> error parsing %s interval duration: %v\n", mode, err)
 50→		}
 51→		if d <= 0 {
 52→			return
 53→		}
 54→
 55→		ticker := time.NewTicker(d)
 56→		defer ticker.Stop()
 57→
 58→		for {
 59→			select {
 60→			case <-ctx.Done():
 61→				return
 62→			case <-ticker.C:
 63→				t := time.Now().Add(-d)
 64→				cclog.Infof("[METRICSTORE]> start %s checkpoints (older than %s)...", mode, t.Format(time.RFC3339))
 65→
 66→				n, err := CleanupCheckpoints(Keys.Checkpoints.RootDir, cleanupDir, t.Unix(), delete)
 67→
 68→				if err != nil {
 69→					cclog.Errorf("[METRICSTORE]> %s failed: %s", mode, err.Error())
 70→				} else {
 71→					if delete {
 72→						cclog.Infof("[METRICSTORE]> done: %d checkpoints deleted", n)
 73→					} else {
 74→						cclog.Infof("[METRICSTORE]> done: %d checkpoint files archived to parquet", n)
 75→					}
 76→				}
 77→			}
 78→		}
 79→	})
 80→}
 81→
 82→var ErrNoNewArchiveData error = errors.New("all data already archived")
 83→
 84→// CleanupCheckpoints deletes or archives all checkpoint files older than `from`.
 85→// When archiving, consolidates all hosts per cluster into a single Parquet file.
 86→func CleanupCheckpoints(checkpointsDir, cleanupDir string, from int64, deleteInstead bool) (int, error) {
 87→	if deleteInstead {
 88→		return deleteCheckpoints(checkpointsDir, from)
 89→	}
 90→
 91→	return archiveCheckpoints(checkpointsDir, cleanupDir, from)
 92→}
 93→
 94→// deleteCheckpoints removes checkpoint files older than `from` across all clusters/hosts.
 95→func deleteCheckpoints(checkpointsDir string, from int64) (int, error) {
 96→	entries1, err := os.ReadDir(checkpointsDir)
 97→	if err != nil {
 98→		return 0, err
 99→	}
100→
101→	type workItem struct {
102→		dir            string
103→		cluster, host  string
104→	}
105→
106→	var wg sync.WaitGroup
107→	n, errs := int32(0), int32(0)
108→	work := make(chan workItem, Keys.NumWorkers)
109→
110→	wg.Add(Keys.NumWorkers)
111→	for worker := 0; worker < Keys.NumWorkers; worker++ {
112→		go func() {
113→			defer wg.Done()
114→			for item := range work {
115→				entries, err := os.ReadDir(item.dir)
116→				if err != nil {
117→					cclog.Errorf("error reading %s/%s: %s", item.cluster, item.host, err.Error())
118→					atomic.AddInt32(&errs, 1)
119→					continue
120→				}
121→
122→				files, err := findFiles(entries, from, false)
123→				if err != nil {
124→					cclog.Errorf("error finding files in %s/%s: %s", item.cluster, item.host, err.Error())
125→					atomic.AddInt32(&errs, 1)
126→					continue
127→				}
128→
129→				for _, checkpoint := range files {
130→					if err := os.Remove(filepath.Join(item.dir, checkpoint)); err != nil {
131→						cclog.Errorf("error deleting %s/%s/%s: %s", item.cluster, item.host, checkpoint, err.Error())
132→						atomic.AddInt32(&errs, 1)
133→					} else {
134→						atomic.AddInt32(&n, 1)
135→					}
136→				}
137→			}
138→		}()
139→	}
140→
141→	for _, de1 := range entries1 {
142→		entries2, e := os.ReadDir(filepath.Join(checkpointsDir, de1.Name()))
143→		if e != nil {
144→			err = e
145→			continue
146→		}
147→
148→		for _, de2 := range entries2 {
149→			work <- workItem{
150→				dir:     filepath.Join(checkpointsDir, de1.Name(), de2.Name()),
151→				cluster: de1.Name(),
152→				host:    de2.Name(),
153→			}
154→		}
155→	}
156→
157→	close(work)
158→	wg.Wait()
159→
160→	if err != nil {
161→		return int(n), err
162→	}
163→	if errs > 0 {
164→		return int(n), fmt.Errorf("%d errors happened while deleting (%d successes)", errs, n)
165→	}
166→	return int(n), nil
167→}
168→
169→// archiveCheckpoints archives checkpoint files to Parquet format.
170→// Produces one Parquet file per cluster: <cleanupDir>/<cluster>/<timestamp>.parquet
171→// Each host's rows are written as a separate row group to avoid accumulating
172→// all data in memory at once.
173→func archiveCheckpoints(checkpointsDir, cleanupDir string, from int64) (int, error) {
174→	cclog.Info("[METRICSTORE]> start archiving checkpoints to parquet")
175→	startTime := time.Now()
176→
177→	clusterEntries, err := os.ReadDir(checkpointsDir)
178→	if err != nil {
179→		return 0, err
180→	}
181→
182→	totalFiles := 0
183→
184→	for _, clusterEntry := range clusterEntries {
185→		if !clusterEntry.IsDir() {
186→			continue
187→		}
188→
189→		cluster := clusterEntry.Name()
190→		hostEntries, err := os.ReadDir(filepath.Join(checkpointsDir, cluster))
191→		if err != nil {
192→			return totalFiles, err
193→		}
194→
195→		// Stream per-host rows to parquet writer via worker pool
196→		type hostResult struct {
197→			rows  []ParquetMetricRow
198→			files []string // checkpoint filenames to delete after successful write
199→			dir   string   // checkpoint directory for this host
200→		}
201→
202→		results := make(chan hostResult, len(hostEntries))
203→		work := make(chan struct {
204→			dir, host string
205→		}, Keys.NumWorkers)
206→
207→		var wg sync.WaitGroup
208→		errs := int32(0)
209→
210→		wg.Add(Keys.NumWorkers)
211→		for w := 0; w < Keys.NumWorkers; w++ {
212→			go func() {
213→				defer wg.Done()
214→				for item := range work {
215→					rows, files, err := archiveCheckpointsToParquet(item.dir, cluster, item.host, from)
216→					if err != nil {
217→						cclog.Errorf("[METRICSTORE]> error reading checkpoints for %s/%s: %s", cluster, item.host, err.Error())
218→						atomic.AddInt32(&errs, 1)
219→						continue
220→					}
221→					if len(rows) > 0 {
222→						results <- hostResult{rows: rows, files: files, dir: item.dir}
223→					}
224→				}
225→			}()
226→		}
227→
228→		go func() {
229→			for _, hostEntry := range hostEntries {
230→				if !hostEntry.IsDir() {
231→					continue
232→				}
233→				dir := filepath.Join(checkpointsDir, cluster, hostEntry.Name())
234→				work <- struct {
235→					dir, host string
236→				}{dir: dir, host: hostEntry.Name()}
237→			}
238→			close(work)
239→			wg.Wait()
240→			close(results)
241→		}()
242→
243→		// Open streaming writer and write each host's rows as a row group
244→		parquetFile := filepath.Join(cleanupDir, cluster, fmt.Sprintf("%d.parquet", from))
245→		writer, err := newParquetArchiveWriter(parquetFile)
246→		if err != nil {
247→			// Drain results channel to unblock workers
248→			for range results {
249→			}
250→			return totalFiles, fmt.Errorf("creating parquet writer for cluster %s: %w", cluster, err)
251→		}
252→
253→		type deleteItem struct {
254→			dir   string
255→			files []string
256→		}
257→		var toDelete []deleteItem
258→		writeErr := error(nil)
259→
260→		for r := range results {
261→			if writeErr == nil {
262→				sortParquetRows(r.rows)
263→				if err := writer.WriteHostRows(r.rows); err != nil {
264→					writeErr = err
265→				}
266→			}
267→			// Always track files for deletion (even if write failed, we still drain)
268→			toDelete = append(toDelete, deleteItem{dir: r.dir, files: r.files})
269→		}
270→
271→		if err := writer.Close(); err != nil && writeErr == nil {
272→			writeErr = err
273→		}
274→
275→		if errs > 0 {
276→			return totalFiles, fmt.Errorf("%d errors reading checkpoints for cluster %s", errs, cluster)
277→		}
278→
279→		if writer.count == 0 {
280→			// No data written — remove empty file
281→			os.Remove(parquetFile)
282→			continue
283→		}
284→
285→		if writeErr != nil {
286→			os.Remove(parquetFile)
287→			return totalFiles, fmt.Errorf("writing parquet archive for cluster %s: %w", cluster, writeErr)
288→		}
289→
290→		// Delete archived checkpoint files
291→		for _, item := range toDelete {
292→			for _, file := range item.files {
293→				filename := filepath.Join(item.dir, file)
294→				if err := os.Remove(filename); err != nil {
295→					cclog.Warnf("[METRICSTORE]> could not remove archived checkpoint %s: %v", filename, err)
296→				} else {
297→					totalFiles++
298→				}
299→			}
300→		}
301→
302→		cclog.Infof("[METRICSTORE]> archived %d rows from %d files for cluster %s to %s",
303→			writer.count, totalFiles, cluster, parquetFile)
304→	}
305→
306→	cclog.Infof("[METRICSTORE]> archiving checkpoints completed in %s (%d files)", time.Since(startTime).Round(time.Millisecond), totalFiles)
307→	return totalFiles, nil
308→}
