  6→package metricstore
  7→
  8→import (
  9→	"bufio"
 10→	"encoding/binary"
 11→	"encoding/json"
 12→	"fmt"
 13→	"os"
 14→	"path/filepath"
 15→	"sort"
 16→
 17→	cclog "github.com/ClusterCockpit/cc-lib/v2/ccLogger"
 18→	pq "github.com/parquet-go/parquet-go"
 19→)
 20→
 21→// ParquetMetricRow is the long-format schema for archived metric data.
 22→// One row per (host, metric, scope, scope_id, timestamp) data point.
 23→// Sorted by (cluster, hostname, metric, timestamp) for optimal compression.
 24→type ParquetMetricRow struct {
 25→	Cluster   string  `parquet:"cluster"`
 26→	Hostname  string  `parquet:"hostname"`
 27→	Metric    string  `parquet:"metric"`
 28→	Scope     string  `parquet:"scope"`
 29→	ScopeID   string  `parquet:"scope_id"`
 30→	Timestamp int64   `parquet:"timestamp"`
 31→	Frequency int64   `parquet:"frequency"`
 32→	Value     float32 `parquet:"value"`
 33→}
 34→
 35→// flattenCheckpointFile recursively converts a CheckpointFile tree into Parquet rows.
 36→// The scope path is built from the hierarchy: host level is "node", then child names
 37→// map to scope/scope_id (e.g., "socket0" → scope="socket", scope_id="0").
 38→func flattenCheckpointFile(cf *CheckpointFile, cluster, hostname, scope, scopeID string, rows []ParquetMetricRow) []ParquetMetricRow {
 39→	for metricName, cm := range cf.Metrics {
 40→		ts := cm.Start
 41→		for _, v := range cm.Data {
 42→			if !v.IsNaN() {
 43→				rows = append(rows, ParquetMetricRow{
 44→					Cluster:   cluster,
 45→					Hostname:  hostname,
 46→					Metric:    metricName,
 47→					Scope:     scope,
 48→					ScopeID:   scopeID,
 49→					Timestamp: ts,
 50→					Frequency: cm.Frequency,
 51→					Value:     float32(v),
 52→				})
 53→			}
 54→			ts += cm.Frequency
 55→		}
 56→	}
 57→
 58→	for childName, childCf := range cf.Children {
 59→		childScope, childScopeID := parseScopeFromName(childName)
 60→		rows = flattenCheckpointFile(childCf, cluster, hostname, childScope, childScopeID, rows)
 61→	}
 62→
 63→	return rows
 64→}
 65→
 66→// parseScopeFromName infers scope and scope_id from a child level name.
 67→// Examples: "socket0" → ("socket", "0"), "core12" → ("core", "12"),
 68→// "a0" (accelerator) → ("accelerator", "0").
 69→// If the name doesn't match known patterns, it's used as-is for scope with empty scope_id.
 70→func parseScopeFromName(name string) (string, string) {
 71→	prefixes := []struct {
 72→		prefix string
 73→		scope  string
 74→	}{
 75→		{"socket", "socket"},
 76→		{"memoryDomain", "memoryDomain"},
 77→		{"core", "core"},
 78→		{"hwthread", "hwthread"},
 79→		{"cpu", "hwthread"},
 80→		{"accelerator", "accelerator"},
 81→	}
 82→
 83→	for _, p := range prefixes {
 84→		if len(name) > len(p.prefix) && name[:len(p.prefix)] == p.prefix {
 85→			id := name[len(p.prefix):]
 86→			if len(id) > 0 && id[0] >= '0' && id[0] <= '9' {
 87→				return p.scope, id
 88→			}
 89→		}
 90→	}
 91→
 92→	return name, ""
 93→}
 94→
 95→// parquetArchiveWriter supports incremental writes to a Parquet file.
 96→// Each call to WriteHostRows writes one row group (typically one host's data),
 97→// avoiding accumulation of all rows in memory.
 98→type parquetArchiveWriter struct {
 99→	writer *pq.GenericWriter[ParquetMetricRow]
100→	bw     *bufio.Writer
101→	f      *os.File
102→	count  int
103→}
104→
105→// newParquetArchiveWriter creates a streaming Parquet writer with Zstd compression.
106→func newParquetArchiveWriter(filename string) (*parquetArchiveWriter, error) {
107→	if err := os.MkdirAll(filepath.Dir(filename), CheckpointDirPerms); err != nil {
108→		return nil, fmt.Errorf("creating archive directory: %w", err)
109→	}
110→
111→	f, err := os.OpenFile(filename, os.O_CREATE|os.O_WRONLY|os.O_TRUNC, CheckpointFilePerms)
112→	if err != nil {
113→		return nil, fmt.Errorf("creating parquet file: %w", err)
114→	}
115→
116→	bw := bufio.NewWriterSize(f, 1<<20) // 1MB write buffer
117→
118→	writer := pq.NewGenericWriter[ParquetMetricRow](bw,
119→		pq.Compression(&pq.Zstd),
120→	)
121→
122→	return &parquetArchiveWriter{writer: writer, bw: bw, f: f}, nil
123→}
124→
125→// WriteHostRows sorts rows by (metric, timestamp) in-place, writes them,
126→// and flushes to create a separate row group.
127→func (w *parquetArchiveWriter) WriteHostRows(rows []ParquetMetricRow) error {
128→	sort.Slice(rows, func(i, j int) bool {
129→		if rows[i].Metric != rows[j].Metric {
130→			return rows[i].Metric < rows[j].Metric
131→		}
132→		return rows[i].Timestamp < rows[j].Timestamp
133→	})
134→
135→	if _, err := w.writer.Write(rows); err != nil {
136→		return fmt.Errorf("writing parquet rows: %w", err)
137→	}
138→
139→	if err := w.writer.Flush(); err != nil {
140→		return fmt.Errorf("flushing parquet row group: %w", err)
141→	}
142→
143→	w.count += len(rows)
144→	return nil
145→}
146→
147→// Close finalises the Parquet file (footer, buffered I/O, file handle).
148→func (w *parquetArchiveWriter) Close() error {
149→	if err := w.writer.Close(); err != nil {
150→		w.f.Close()
151→		return fmt.Errorf("closing parquet writer: %w", err)
152→	}
153→
154→	if err := w.bw.Flush(); err != nil {
155→		w.f.Close()
156→		return fmt.Errorf("flushing parquet file: %w", err)
157→	}
158→
159→	return w.f.Close()
160→}
161→
162→// sortParquetRows sorts rows by (metric, timestamp) in-place.
163→func sortParquetRows(rows []ParquetMetricRow) {
164→	sort.Slice(rows, func(i, j int) bool {
165→		if rows[i].Metric != rows[j].Metric {
166→			return rows[i].Metric < rows[j].Metric
167→		}
168→		return rows[i].Timestamp < rows[j].Timestamp
169→	})
170→}
