172→// loadCheckpointFileFromDisk reads a JSON or binary checkpoint file and returns
173→// a CheckpointFile. Used by the Parquet archiver to read checkpoint data
174→// before converting it to Parquet format.
175→func loadCheckpointFileFromDisk(filename string) (*CheckpointFile, error) {
176→	f, err := os.Open(filename)
177→	if err != nil {
178→		return nil, err
179→	}
180→	defer f.Close()
181→
182→	ext := filepath.Ext(filename)
183→	switch ext {
184→	case ".json":
185→		cf := &CheckpointFile{}
186→		br := bufio.NewReader(f)
187→		if err := json.NewDecoder(br).Decode(cf); err != nil {
188→			return nil, fmt.Errorf("decoding JSON checkpoint %s: %w", filename, err)
189→		}
190→		return cf, nil
191→
192→	case ".bin":
193→		br := bufio.NewReader(f)
194→		var magic uint32
195→		if err := binary.Read(br, binary.LittleEndian, &magic); err != nil {
196→			return nil, fmt.Errorf("reading magic from %s: %w", filename, err)
197→		}
198→		if magic != snapFileMagic {
199→			return nil, fmt.Errorf("invalid snapshot magic in %s: 0x%08X", filename, magic)
200→		}
201→		var fileFrom, fileTo int64
202→		if err := binary.Read(br, binary.LittleEndian, &fileFrom); err != nil {
203→			return nil, fmt.Errorf("reading from-timestamp from %s: %w", filename, err)
204→		}
205→		if err := binary.Read(br, binary.LittleEndian, &fileTo); err != nil {
206→			return nil, fmt.Errorf("reading to-timestamp from %s: %w", filename, err)
207→		}
208→		cf, err := readBinaryLevel(br)
209→		if err != nil {
210→			return nil, fmt.Errorf("reading binary level from %s: %w", filename, err)
211→		}
212→		cf.From = fileFrom
213→		cf.To = fileTo
214→		return cf, nil
215→
216→	default:
217→		return nil, fmt.Errorf("unsupported checkpoint extension: %s", ext)
218→	}
219→}
