  5→
  6→// This file implements checkpoint persistence for the in-memory metric store.
  7→//
  8→// Checkpoints enable graceful restarts by periodically saving in-memory metric
  9→// data to disk in JSON or binary format. The checkpoint system:
 10→//
 11→// Key Features:
 12→//   - Periodic background checkpointing via the Checkpointing() worker
 13→//   - Two format families: JSON (human-readable) and WAL+binary (compact, crash-safe)
 14→//   - Parallel checkpoint creation and loading using worker pools
 15→//   - Hierarchical file organization: checkpoint_dir/cluster/host/timestamp.{json|bin}
 16→//   - WAL file: checkpoint_dir/cluster/host/current.wal (append-only, per-entry)
 17→//   - Only saves unarchived data (archived data is already persisted elsewhere)
 18→//   - GC optimization during loading to prevent excessive heap growth
 19→//
 20→// Checkpoint Workflow:
 21→//  1. Init() loads checkpoints within retention window at startup
 22→//  2. Checkpointing() worker periodically saves new data
 23→//  3. Shutdown() writes final checkpoint before exit
 24→//
 25→// File Organization:
 26→//
 27→//	checkpoints/
 28→//	  cluster1/
 29→//	    host001/
 30→//	      1234567890.json  (JSON format: full subtree snapshot)
 31→//	      1234567890.bin   (binary format: full subtree snapshot)
 32→//	      current.wal      (WAL format: append-only per-entry log)
 33→//	    host002/
 34→//	      ...
 35→package metricstore
 36→
 37→import (
 38→	"bufio"
 39→	"context"
 40→	"encoding/json"
 41→	"errors"
 42→	"fmt"
 43→	"io/fs"
 44→	"os"
 45→	"path"
 46→	"path/filepath"
 47→	"sort"
 48→	"strconv"
 49→	"strings"
 50→	"sync"
 51→	"sync/atomic"
 52→	"time"
 53→
 54→	cclog "github.com/ClusterCockpit/cc-lib/v2/ccLogger"
 55→	"github.com/ClusterCockpit/cc-lib/v2/schema"
 56→)
 57→
 58→const (
 59→	CheckpointFilePerms = 0o644                    // File permissions for checkpoint files
 60→	CheckpointDirPerms  = 0o755                    // Directory permissions for checkpoint directories
 61→	GCTriggerInterval   = DefaultGCTriggerInterval // Interval for triggering GC during checkpoint loading
 62→)
 63→
 64→// CheckpointMetrics represents metric data in a checkpoint file.
 65→// Whenever the structure changes, update MarshalJSON as well!
 66→type CheckpointMetrics struct {
 67→	Data      []schema.Float `json:"data"`
 68→	Frequency int64          `json:"frequency"`
 69→	Start     int64          `json:"start"`
 70→}
 71→
 72→// CheckpointFile represents the hierarchical structure of a checkpoint file.
 73→// It mirrors the Level tree structure from the MemoryStore.
 74→type CheckpointFile struct {
 75→	Metrics  map[string]*CheckpointMetrics `json:"metrics"`
 76→	Children map[string]*CheckpointFile    `json:"children"`
 77→	From     int64                         `json:"from"`
 78→	To       int64                         `json:"to"`
 79→}
 80→
 81→// lastCheckpoint tracks the timestamp of the last checkpoint creation.
 82→var (
 83→	lastCheckpoint   time.Time
 84→	lastCheckpointMu sync.Mutex
 85→)
 86→
 87→// Checkpointing starts a background worker that periodically saves metric data to disk.
 88→//
 89→// Checkpoints are written every 12 hours (hardcoded).
 90→//
 91→// Format behaviour:
 92→//   - "json": Periodic checkpointing every checkpointInterval
 93→//   - "wal":  Periodic binary snapshots + WAL rotation every checkpointInterval
 94→func Checkpointing(wg *sync.WaitGroup, ctx context.Context) {
 95→	lastCheckpointMu.Lock()
 96→	lastCheckpoint = time.Now()
 97→	lastCheckpointMu.Unlock()
 98→
 99→	ms := GetMemoryStore()
100→
101→	wg.Go(func() {
102→
103→		d := 12 * time.Hour // default checkpoint interval
104→		if Keys.CheckpointInterval != "" {
105→			parsed, err := time.ParseDuration(Keys.CheckpointInterval)
106→			if err != nil {
107→				cclog.Errorf("[METRICSTORE]> invalid checkpoint-interval %q: %s, using default 12h", Keys.CheckpointInterval, err)
108→			} else {
109→				d = parsed
110→			}
111→		}
112→
113→		ticker := time.NewTicker(d)
114→		defer ticker.Stop()
115→
116→		for {
117→			select {
118→			case <-ctx.Done():
119→				return
120→			case <-ticker.C:
121→				lastCheckpointMu.Lock()
122→				from := lastCheckpoint
123→				lastCheckpointMu.Unlock()
124→
125→				now := time.Now()
126→				cclog.Infof("[METRICSTORE]> start checkpointing (starting at %s)...", from.Format(time.RFC3339))
127→
128→				if Keys.Checkpoints.FileFormat == "wal" {
129→					n, hostDirs, err := ms.ToCheckpointWAL(Keys.Checkpoints.RootDir, from.Unix(), now.Unix())
130→					if err != nil {
131→						cclog.Errorf("[METRICSTORE]> binary checkpointing failed: %s", err.Error())
132→					} else {
133→						cclog.Infof("[METRICSTORE]> done: %d binary snapshot files created", n)
134→						lastCheckpointMu.Lock()
135→						lastCheckpoint = now
136→						lastCheckpointMu.Unlock()
137→						// Rotate WAL files for successfully checkpointed hosts.
138→						RotateWALFiles(hostDirs)
139→					}
140→				} else {
141→					n, err := ms.ToCheckpoint(Keys.Checkpoints.RootDir, from.Unix(), now.Unix())
142→					if err != nil {
143→						cclog.Errorf("[METRICSTORE]> checkpointing failed: %s", err.Error())
144→					} else {
145→						cclog.Infof("[METRICSTORE]> done: %d checkpoint files created", n)
146→						lastCheckpointMu.Lock()
147→						lastCheckpoint = now
148→						lastCheckpointMu.Unlock()
149→					}
150→				}
151→			}
152→		}
153→	})
154→}
155→
156→// MarshalJSON provides optimized JSON encoding for CheckpointMetrics.
157→//
158→// Since schema.Float has custom MarshalJSON, serializing []Float has significant overhead.
159→// This method manually constructs JSON to avoid allocations and interface conversions.
160→func (cm *CheckpointMetrics) MarshalJSON() ([]byte, error) {
161→	buf := make([]byte, 0, 128+len(cm.Data)*8)
162→	buf = append(buf, `{"frequency":`...)
163→	buf = strconv.AppendInt(buf, cm.Frequency, 10)
164→	buf = append(buf, `,"start":`...)
165→	buf = strconv.AppendInt(buf, cm.Start, 10)
166→	buf = append(buf, `,"data":[`...)
167→	for i, x := range cm.Data {
168→		if i != 0 {
169→			buf = append(buf, ',')
170→		}
171→		if x.IsNaN() {
172→			buf = append(buf, `null`...)
173→		} else {
174→			buf = strconv.AppendFloat(buf, float64(x), 'f', 1, 32)
175→		}
176→	}
177→	buf = append(buf, `]}`...)
178→	return buf, nil
179→}
180→
181→// ToCheckpoint writes metric data to checkpoint files in parallel (JSON format).
182→//
183→// Metrics at root and cluster levels are skipped. One file per host is created.
184→// Uses worker pool (Keys.NumWorkers) for parallel processing. Only locks one host
185→// at a time, allowing concurrent writes/reads to other hosts.
186→//
187→// Returns the number of checkpoint files created and any errors encountered.
188→func (m *MemoryStore) ToCheckpoint(dir string, from, to int64) (int, error) {
189→	// Pre-calculate capacity by counting cluster/host pairs
190→	m.root.lock.RLock()
191→	totalHosts := 0
192→	for _, l1 := range m.root.children {
193→		l1.lock.RLock()
194→		totalHosts += len(l1.children)
195→		l1.lock.RUnlock()
196→	}
197→	m.root.lock.RUnlock()
198→
199→	levels := make([]*Level, 0, totalHosts)
200→	selectors := make([][]string, 0, totalHosts)
201→
202→	m.root.lock.RLock()
203→	for sel1, l1 := range m.root.children {
204→		l1.lock.RLock()
205→		for sel2, l2 := range l1.children {
206→			levels = append(levels, l2)
207→			selectors = append(selectors, []string{sel1, sel2})
208→		}
209→		l1.lock.RUnlock()
210→	}
211→	m.root.lock.RUnlock()
212→
213→	type workItem struct {
214→		level    *Level
215→		dir      string
216→		selector []string
217→	}
218→
219→	n, errs := int32(0), int32(0)
220→
221→	var wg sync.WaitGroup
222→	wg.Add(Keys.NumWorkers)
223→	work := make(chan workItem, Keys.NumWorkers*2)
224→	for worker := 0; worker < Keys.NumWorkers; worker++ {
225→		go func() {
226→			defer wg.Done()
227→
228→			for workItem := range work {
229→				if err := workItem.level.toCheckpoint(workItem.dir, from, to, m); err != nil {
230→					if err == ErrNoNewArchiveData {
231→						continue
232→					}
233→
234→					cclog.Errorf("[METRICSTORE]> error while checkpointing %#v: %s", workItem.selector, err.Error())
235→					atomic.AddInt32(&errs, 1)
236→				} else {
237→					atomic.AddInt32(&n, 1)
238→				}
239→			}
240→		}()
241→	}
242→
243→	for i := 0; i < len(levels); i++ {
244→		dir := path.Join(dir, path.Join(selectors[i]...))
245→		work <- workItem{
246→			level:    levels[i],
247→			dir:      dir,
248→			selector: selectors[i],
249→		}
250→	}
251→
252→	close(work)
253→	wg.Wait()
254→
255→	if errs > 0 {
256→		return int(n), fmt.Errorf("[METRICSTORE]> %d errors happened while creating checkpoints (%d successes)", errs, n)
257→	}
258→	return int(n), nil
259→}
260→
261→// toCheckpointFile recursively converts a Level tree to CheckpointFile structure.
262→// Skips metrics that are already archived. Returns nil if no unarchived data exists.
263→func (l *Level) toCheckpointFile(from, to int64, m *MemoryStore) (*CheckpointFile, error) {
264→	l.lock.RLock()
265→	defer l.lock.RUnlock()
266→
267→	retval := &CheckpointFile{
268→		From:     from,
269→		To:       to,
270→		Metrics:  make(map[string]*CheckpointMetrics),
271→		Children: make(map[string]*CheckpointFile),
272→	}
273→
274→	for metric, minfo := range m.Metrics {
275→		b := l.metrics[minfo.offset]
276→		if b == nil {
277→			continue
278→		}
279→
280→		allArchived := true
281→		b.iterFromTo(from, to, func(b *buffer) error {
282→			if !b.archived {
283→				allArchived = false
284→				return fmt.Errorf("stop") // Early termination signal
285→			}
286→			return nil
287→		})
288→
289→		if allArchived {
290→			continue
291→		}
292→
293→		data := make([]schema.Float, (to-from)/b.frequency+1)
294→		data, start, end, err := b.read(from, to, data)
295→		if err != nil {
296→			return nil, err
297→		}
298→
299→		for i := int((end - start) / b.frequency); i < len(data); i++ {
300→			data[i] = schema.NaN
301→		}
302→
303→		retval.Metrics[metric] = &CheckpointMetrics{
304→			Frequency: b.frequency,
305→			Start:     start,
306→			Data:      data,
307→		}
308→	}
309→
310→	for name, child := range l.children {
311→		val, err := child.toCheckpointFile(from, to, m)
312→		if err != nil {
313→			return nil, err
314→		}
315→
316→		if val != nil {
317→			retval.Children[name] = val
318→		}
319→	}
320→
321→	if len(retval.Children) == 0 && len(retval.Metrics) == 0 {
322→		return nil, nil
323→	}
324→
325→	return retval, nil
326→}
327→
328→// toCheckpoint writes a Level's data to a JSON checkpoint file.
329→// Creates directory if needed. Returns ErrNoNewArchiveData if nothing to save.
330→func (l *Level) toCheckpoint(dir string, from, to int64, m *MemoryStore) error {
331→	cf, err := l.toCheckpointFile(from, to, m)
332→	if err != nil {
333→		return err
334→	}
335→
336→	if cf == nil {
337→		return ErrNoNewArchiveData
338→	}
339→
340→	filepath := path.Join(dir, fmt.Sprintf("%d.json", from))
341→	f, err := os.OpenFile(filepath, os.O_CREATE|os.O_WRONLY|os.O_TRUNC, CheckpointFilePerms)
342→	if err != nil && os.IsNotExist(err) {
343→		err = os.MkdirAll(dir, CheckpointDirPerms)
344→		if err == nil {
345→			f, err = os.OpenFile(filepath, os.O_CREATE|os.O_WRONLY|os.O_TRUNC, CheckpointFilePerms)
346→		}
347→	}
348→	if err != nil {
349→		return err
350→	}
351→	defer f.Close()
352→
353→	bw := bufio.NewWriter(f)
354→	if err = json.NewEncoder(bw).Encode(cf); err != nil {
355→		return err
356→	}
357→
358→	return bw.Flush()
359→}
360→
361→// enqueueCheckpointHosts traverses checkpoint directory and enqueues cluster/host pairs.
362→// Returns error if directory structure is invalid.
363→func enqueueCheckpointHosts(dir string, work chan<- [2]string) error {
364→	clustersDir, err := os.ReadDir(dir)
365→	if err != nil {
366→		return err
367→	}
368→
369→	for _, clusterDir := range clustersDir {
370→		if !clusterDir.IsDir() {
371→			return errors.New("[METRICSTORE]> expected only directories at first level of checkpoints/ directory")
372→		}
373→
374→		hostsDir, err := os.ReadDir(filepath.Join(dir, clusterDir.Name()))
375→		if err != nil {
376→			return err
377→		}
378→
379→		for _, hostDir := range hostsDir {
380→			if !hostDir.IsDir() {
381→				return errors.New("[METRICSTORE]> expected only directories at second level of checkpoints/ directory")
382→			}
383→
384→			work <- [2]string{clusterDir.Name(), hostDir.Name()}
385→		}
386→	}
387→
388→	return nil
389→}
390→
391→// FromCheckpoint loads checkpoint files from disk into memory in parallel.
392→//
393→// Uses worker pool to load cluster/host combinations. Returns number of files
394→// loaded and any errors.
395→func (m *MemoryStore) FromCheckpoint(dir string, from int64) (int, error) {
396→	var wg sync.WaitGroup
397→	work := make(chan [2]string, Keys.NumWorkers*4)
398→	n, errs := int32(0), int32(0)
399→
400→	wg.Add(Keys.NumWorkers)
401→	for worker := 0; worker < Keys.NumWorkers; worker++ {
402→		go func() {
403→			defer wg.Done()
404→			for host := range work {
405→				lvl := m.root.findLevelOrCreate(host[:], len(m.Metrics))
406→				nn, err := lvl.fromCheckpoint(m, filepath.Join(dir, host[0], host[1]), from)
407→				if err != nil {
408→					cclog.Errorf("[METRICSTORE]> error while loading checkpoints for %s/%s: %s", host[0], host[1], err.Error())
409→					atomic.AddInt32(&errs, 1)
410→				}
411→				atomic.AddInt32(&n, int32(nn))
412→			}
413→		}()
414→	}
415→
416→	err := enqueueCheckpointHosts(dir, work)
417→	close(work)
418→	wg.Wait()
419→
420→	if err != nil {
421→		return int(n), err
422→	}
423→
424→	if errs > 0 {
425→		return int(n), fmt.Errorf("[METRICSTORE]> %d errors happened while creating checkpoints (%d successes)", errs, n)
426→	}
427→	return int(n), nil
428→}
429→
430→// FromCheckpointFiles is the main entry point for loading checkpoints at startup.
431→//
432→// Creates checkpoint directory if it doesn't exist. This function must be called
433→// before any writes or reads, and can only be called once.
434→func (m *MemoryStore) FromCheckpointFiles(dir string, from int64) (int, error) {
435→	if _, err := os.Stat(dir); os.IsNotExist(err) {
436→		err := os.MkdirAll(dir, CheckpointDirPerms)
437→		if err != nil {
438→			cclog.Fatalf("[METRICSTORE]> Error creating directory: %#v\n", err)
439→		}
440→		cclog.Debugf("[METRICSTORE]> %#v Directory created successfully", dir)
441→	}
442→
443→	return m.FromCheckpoint(dir, from)
444→}
445→
446→func (l *Level) loadJSONFile(m *MemoryStore, f *os.File, from int64) error {
447→	br := bufio.NewReader(f)
448→	cf := &CheckpointFile{}
449→	if err := json.NewDecoder(br).Decode(cf); err != nil {
450→		return err
451→	}
452→
453→	if cf.To != 0 && cf.To < from {
454→		return nil
455→	}
456→
457→	if err := l.loadFile(cf, m); err != nil {
458→		return err
459→	}
460→
461→	return nil
462→}
463→
464→func (l *Level) loadFile(cf *CheckpointFile, m *MemoryStore) error {
465→	for name, metric := range cf.Metrics {
466→		n := len(metric.Data)
467→		b := &buffer{
468→			frequency: metric.Frequency,
469→			start:     metric.Start,
470→			data:      metric.Data[0:n:n],
471→			prev:      nil,
472→			next:      nil,
473→			archived:  true,
474→		}
475→
476→		minfo, ok := m.Metrics[name]
477→		if !ok {
478→			continue
479→		}
480→
481→		prev := l.metrics[minfo.offset]
482→		if prev == nil {
483→			l.metrics[minfo.offset] = b
484→		} else {
485→			if prev.start > b.start {
486→				return fmt.Errorf("[METRICSTORE]> buffer start time %d is before previous buffer start %d", b.start, prev.start)
487→			}
488→
489→			b.prev = prev
490→			prev.next = b
491→		}
492→		l.metrics[minfo.offset] = b
493→	}
494→
495→	if len(cf.Children) > 0 && l.children == nil {
496→		l.children = make(map[string]*Level)
497→	}
498→
499→	for sel, childCf := range cf.Children {
500→		child, ok := l.children[sel]
501→		if !ok {
502→			child = &Level{
503→				metrics:  make([]*buffer, len(m.Metrics)),
504→				children: nil,
505→			}
506→			l.children[sel] = child
507→		}
508→
509→		if err := child.loadFile(childCf, m); err != nil {
510→			return err
511→		}
512→	}
513→
514→	return nil
515→}
516→
517→// fromCheckpoint loads all checkpoint files (JSON, binary snapshot, WAL) for a
518→// single host directory. Snapshot files are loaded first (sorted by timestamp),
519→// then current.wal is replayed on top.
520→func (l *Level) fromCheckpoint(m *MemoryStore, dir string, from int64) (int, error) {
521→	direntries, err := os.ReadDir(dir)
522→	if err != nil {
523→		if os.IsNotExist(err) {
524→			return 0, nil
525→		}
526→		return 0, err
527→	}
528→
529→	allFiles := make([]fs.DirEntry, 0)
530→	var walEntry fs.DirEntry
531→	filesLoaded := 0
532→
533→	for _, e := range direntries {
534→		if e.IsDir() {
535→			// Legacy: skip subdirectories (only used by old Avro format).
536→			// These are ignored; their data is not loaded.
537→			cclog.Debugf("[METRICSTORE]> skipping subdirectory %s in checkpoint dir %s", e.Name(), dir)
538→			continue
539→		}
540→
541→		name := e.Name()
542→		if strings.HasSuffix(name, ".json") || strings.HasSuffix(name, ".bin") {
543→			allFiles = append(allFiles, e)
544→		} else if name == "current.wal" {
545→			walEntry = e
546→		}
547→		// Silently ignore other files (e.g., .tmp, .bin.tmp from interrupted writes).
548→	}
549→
550→	files, err := findFiles(allFiles, from, true)
551→	if err != nil {
552→		return filesLoaded, err
553→	}
554→
555→	loaders := map[string]func(*MemoryStore, *os.File, int64) error{
556→		".json": l.loadJSONFile,
557→		".bin":  l.loadBinaryFile,
558→	}
559→
560→	for _, filename := range files {
561→		ext := filepath.Ext(filename)
562→		loader := loaders[ext]
563→		if loader == nil {
564→			cclog.Warnf("[METRICSTORE]> unknown extension for checkpoint file %s", filename)
565→			continue
566→		}
567→
568→		err := func() error {
569→			f, err := os.Open(path.Join(dir, filename))
570→			if err != nil {
571→				return err
572→			}
573→			defer f.Close()
574→			return loader(m, f, from)
575→		}()
576→		if err != nil {
577→			return filesLoaded, err
578→		}
579→		filesLoaded++
580→	}
581→
582→	// Replay WAL after all snapshot files so it fills in data since the last snapshot.
583→	if walEntry != nil {
584→		err := func() error {
585→			f, err := os.Open(path.Join(dir, walEntry.Name()))
586→			if err != nil {
587→				return err
588→			}
589→			defer f.Close()
590→			return l.loadWALFile(m, f, from)
591→		}()
592→		if err != nil {
593→			// WAL errors are non-fatal: the snapshot already loaded the bulk of data.
594→			cclog.Warnf("[METRICSTORE]> WAL replay error for %s: %v (data since last snapshot may be missing)", dir, err)
595→		} else {
596→			filesLoaded++
597→		}
598→	}
599→
600→	return filesLoaded, nil
601→}
602→
603→// parseTimestampFromFilename extracts a Unix timestamp from a checkpoint filename.
604→// Supports ".json" (format: "<ts>.json") and ".bin" (format: "<ts>.bin").
605→func parseTimestampFromFilename(name string) (int64, error) {
606→	switch {
607→	case strings.HasSuffix(name, ".json"):
608→		return strconv.ParseInt(name[:len(name)-5], 10, 64)
609→	case strings.HasSuffix(name, ".bin"):
610→		return strconv.ParseInt(name[:len(name)-4], 10, 64)
611→	default:
612→		return 0, fmt.Errorf("unknown checkpoint extension for file %q", name)
613→	}
614→}
615→
616→// findFiles returns filenames from direntries whose timestamps satisfy the filter.
617→// If findMoreRecentFiles is true, returns files with timestamps >= t (plus the
618→// last file before t if t falls between two files).
619→func findFiles(direntries []fs.DirEntry, t int64, findMoreRecentFiles bool) ([]string, error) {
620→	nums := map[string]int64{}
621→	for _, e := range direntries {
622→		name := e.Name()
623→		if !strings.HasSuffix(name, ".json") && !strings.HasSuffix(name, ".bin") {
624→			continue
625→		}
626→
627→		ts, err := parseTimestampFromFilename(name)
628→		if err != nil {
629→			return nil, err
630→		}
631→		nums[name] = ts
632→	}
633→
634→	sort.Slice(direntries, func(i, j int) bool {
635→		a, b := direntries[i], direntries[j]
636→		return nums[a.Name()] < nums[b.Name()]
637→	})
638→
639→	if len(nums) == 0 {
640→		return nil, nil
641→	}
642→
643→	filenames := make([]string, 0)
644→
645→	for i, e := range direntries {
646→		ts1 := nums[e.Name()]
647→
648→		if findMoreRecentFiles && t <= ts1 {
649→			filenames = append(filenames, e.Name())
650→		} else if !findMoreRecentFiles && ts1 <= t && ts1 != 0 {
651→			filenames = append(filenames, e.Name())
652→		}
653→
654→		if i == len(direntries)-1 {
655→			continue
656→		}
657→
658→		enext := direntries[i+1]
659→		ts2 := nums[enext.Name()]
660→
661→		if findMoreRecentFiles {
662→			if ts1 < t && t < ts2 {
663→				filenames = append(filenames, e.Name())
664→			}
665→		}
666→	}
667→
668→	return filenames, nil
669→}
